public function select($id) {
    $user = aboutModel::get($id);
    echo $user->name.'<br/>';
    echo $user->height.'<br/>';
    echo $user->weight.'<br/>';
}

public function all() {
    $user = aboutModel::all();
    foreach($user as $list) {
        echo $list->name.'<br/>';
        echo $list->height.'<br/>';
        echo $list->weight.'<br/>';
    }
}

public function all() {
    $user = aboutModel::all();
    $title = '全部使用者資料';
    $this->assign('title', $title);
    return $this->assign('user', $user)->fetch('getAllUser'); // Don't forget to return on the last line, otherwise you won't see the template~
}
